div.p:
🐛 BUG: Return 0 instead of -ERESTARTSYS
c
// WRONG:
if (wait_event_interruptible(...))
return 0;  // ← looks like EOF!

🐛 WORSE BUG: Use wait_event (not _interruptible)
c
// CATASTROPHICALLY WRONG:
wait_event(mydevice_read_queue,   // ← TASK_UNINTERRUPTIBLE
buffer_data_len > 0);

🐛 SUBTLE BUG: Convert to -EINTR before returning
c
// WRONG:
if (wait_event_interruptible(...))
return -EINTR;  // ← bypasses SA_RESTART!
